const items = $('Input from MAIN').all().map(i => i.json);
const sys = Buffer.from($('Load System').first().json.content,'base64').toString('utf-8');
const usrTemplate = Buffer.from($('Load User').first().json.content,'base64').toString('utf-8');

return items.map(inp => {
  let usr = usrTemplate;
  const a1out = inp.a1_audit||inp.agent_output||{};
  const vars = {
    course_id: inp.course_id||'', chapter_index: inp.chapter_index||0,
    chunk_index: inp.chunk_index||1, source_language: inp.source_language||'fr',
    target_language: inp.target_language||'en-US', html_content: inp.html||inp.html_content||'',
    detected_domain: inp.detected_domain||'',
    a1_audit: JSON.stringify(a1out), a1_outputs: JSON.stringify(inp.a1_outputs||[]),
    domain_validated_tm: JSON.stringify(inp.domain_validated_tm||[]),
    domain_unvalidated_tm: JSON.stringify(inp.domain_unvalidated_tm||[]),
    common_glossary: JSON.stringify(inp.common_glossary||[]),
    score_target: inp.score_target||90
  };
  Object.entries(vars).forEach(([k,v]) => {
    usr = usr.replace(new RegExp('\\{{'+k+'\\}}','g'), String(v));
  });
  return {json:{
    system_prompt: sys, user_message: usr,
    model: 'gpt-5.5-pro-2026-04-23',
 max_tokens: 8000,
    custom_id: (inp.course_id||'x')+'-ch'+(inp.chapter_index||0)+'-ck'+(inp.chunk_index||1)+'-a2',
    agent_name: 'A2 Terminology Architect', course_id: inp.course_id,
    chapter_index: inp.chapter_index, chunk_index: inp.chunk_index,
    pipeline_meta: inp.pipeline_meta||{}
  }};
});

const p = $input.first().json;
const origItems = $('Input from MAIN').all().map(i => i.json);
const results = p.results || [{custom_id: null, parsed_content: p.agent_output}];

const rMap = {};
results.forEach(r => {
  const m = (r.custom_id||'').match(/-ch(\d+)-ck(\d+)-/);
  if(m) rMap[m[1]+'-'+m[2]] = r.parsed_content;
});

if(p.status==='failed'||p.status==='timed_out')
  return origItems.map(orig => ({json:{
    status:'error', agent:'A2 Terminology Architect', error:p.error, escalation:true,
    course_id:p.course_id||orig.course_id,
    chapter_index:orig.chapter_index||0, chunk_index:orig.chunk_index||1
  }}));

return origItems.map(orig => {
  const key = (orig.chapter_index||0)+'-'+(orig.chunk_index||1);
  const ao = rMap[key] || results[0]?.parsed_content || null;
  return {json:{
    status:'ok', agent:'A2 Terminology Architect', agent_output:ao, a2_glossary:ao||{},
    course_id:p.course_id||orig.course_id,
    chapter_index:orig.chapter_index||0, chunk_index:orig.chunk_index||1,
    pipeline_meta:p.pipeline_meta||{},
    html:orig.html||orig.html_content||'', source_html:orig.html||orig.source_html||'',
    a1_audit:orig.a1_audit||orig.a1_audit||{}, a1_outputs:orig.a1_outputs||[],
    source_language:orig.source_language||'fr', target_language:orig.target_language||'en-US',
    target_course_id:orig.target_course_id||'', score_target:orig.score_target||90,
    detected_domain:orig.detected_domain||'', preceding_context:orig.preceding_context||'',
    enabled_modules:orig.enabled_modules||{}, iteration:orig.iteration||1,
    common_glossary:orig.common_glossary||[], domain_validated_tm:orig.domain_validated_tm||[],
    domain_unvalidated_tm:orig.domain_unvalidated_tm||[]
  }};
});

